+func TestPathWithinDir_RootDir(t *testing.T) {
+	if runtime.GOOS == "windows" {
+		t.Skip("root path semantics differ on Windows")
+	}
+	if !pathWithinDir("/tmp/image.png", "/") {
+		t.Fatalf("expected /tmp/image.png to be considered inside /")
+	}
+}
